import { useState, useEffect } from "react";
import { T } from "../../assets/styles/theme";
import {
  Btn, Card, Badge, Avatar, Input, Select,
  StatCard, Table, Tabs, ProgressBar, DonutChart,
  MiniBarChart, PageHeader, ProfileAlert, Modal
} from "../../components/UI";
import { DashLayout } from "../../components/Layout";
import {
  getAdminStats,
  getAdminProfile,
  updateAdminProfile,
  getAllStudents,
  getAllTeachers,
  getAllParents,
  deleteStudent,
  deleteTeacher,
  deleteParent,
  toggleStudent,
  toggleTeacher,
  getAllCourses,
  createCourse,
  updateCourse,
  deleteCourse,
  getAllBatches,
  createBatch,
  deleteBatch,
  getAllFees,
  createFee,
  markFeePaid,
  getAllAnnouncements,
  createAnnouncement,
  deleteAnnouncement,
} from "../../api/auth";


// ─── ADMIN OVERVIEW ───────────────────────────────────────────────────────────
export const AdminOverview = () => {
  const [stats, setStats] = useState({
    totalStudents: 0,
    totalTeachers: 0,
    totalParents: 0,
    totalAdmins: 0,
    totalCourses: 0,
    thisMonthStudents: 0,
    revenueThisMonth: 0,
    activeCourses: 0,
    activeBatches: 0,
  });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchDashboard();
  }, []);

  const fetchDashboard = async () => {
    try {
      setLoading(true);
      setError(null);
      const data = await getAdminStats();
      console.log("Stats from API:", data);
      setStats({
        totalStudents:    data?.totalStudents    ?? 0,
        totalTeachers:    data?.totalTeachers    ?? 0,
        totalParents:     data?.totalParents     ?? 0,
        totalAdmins:      data?.totalAdmins      ?? 0,
        totalCourses:     data?.totalCourses     ?? 0,
        thisMonthStudents:data?.thisMonthStudents ?? 0,
        // revenueThisMonth may be null if no payments yet
        revenueThisMonth: data?.revenueThisMonth != null
          ? `₹${Number(data.revenueThisMonth).toLocaleString("en-IN")}`
          : "₹0",
        activeCourses:    data?.activeCourses    ?? 0,
        activeBatches:    data?.activeBatches    ?? 0,
      });
    } catch (err) {
      console.error("Dashboard error:", err);
      setError("Failed to load dashboard stats.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fade-up">
      <PageHeader
        title="Admin Dashboard"
        subtitle="Full system overview — Zenelait InfoTech Academy"
        actions={[
          <Btn size="sm" variant="ghost" onClick={fetchDashboard}>
            🔄 Refresh
          </Btn>
        ]}
      />

      {error && (
        <div style={{
          background: `${T.accentR}20`,
          border: `1px solid ${T.accentR}40`,
          borderRadius: 10,
          padding: "10px 16px",
          marginBottom: 18,
          fontSize: 13,
          color: T.accentR,
        }}>
          ⚠️ {error}
        </div>
      )}

      {/* ── Row 1: People counts ── */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 18, marginBottom: 18 }}>
        <StatCard
          icon="👨‍🎓"
          label="Total Students"
          value={loading ? "…" : stats.totalStudents}
          change={loading ? "" : `↑ ${stats.thisMonthStudents} this month`}
          color={T.primaryL}
        />
        <StatCard
          icon="👨‍🏫"
          label="Teachers"
          value={loading ? "…" : stats.totalTeachers}
          color={T.accent}
        />
        <StatCard
          icon="👨‍👩‍👦"
          label="Parents"
          value={loading ? "…" : stats.totalParents}
          color={T.accentR}
        />
        <StatCard
          icon="💰"
          label="Revenue (This Month)"
          value={loading ? "…" : stats.revenueThisMonth}
          color={T.accentY}
        />
      </div>

      {/* ── Row 2: Course / Batch / misc counts ── */}
