// ─── MANAGE USERS ─────────────────────────────────────────────────────────────
export const AdminUsers = () => {
  const [tab, setTab]         = useState("Students");
  const [modal, setModal]     = useState(false);
  const [students, setStudents] = useState([]);
  const [teachers, setTeachers] = useState([]);
  const [parents, setParents]   = useState([]);
  const [loading, setLoading]   = useState(false);

  useEffect(() => { loadAll(); }, []);

  const loadAll = async () => {
    setLoading(true);
    try {
      const [s, t, p] = await Promise.all([getAllStudents(), getAllTeachers(), getAllParents()]);
      setStudents(Array.isArray(s) ? s : []);
      setTeachers(Array.isArray(t) ? t : []);
      setParents(Array.isArray(p)  ? p : []);
    } catch (err) { console.error(err); }
    finally { setLoading(false); }
  };

  const handleDeleteStudent = async (id) => {
    if (!confirm("Delete this student?")) return;
    await deleteStudent(id).catch(console.error);
    setStudents(s => s.filter(x => x.id !== id));
  };

  const handleDeleteTeacher = async (id) => {
    if (!confirm("Delete this teacher?")) return;
    await deleteTeacher(id).catch(console.error);
    setTeachers(t => t.filter(x => x.id !== id));
  };

  const handleDeleteParent = async (id) => {
    if (!confirm("Delete this parent?")) return;
    await deleteParent(id).catch(console.error);
    setParents(p => p.filter(x => x.id !== id));
  };

  const handleToggleStudent = async (id, active) => {
    await toggleStudent(id, active).catch(console.error);
    setStudents(s => s.map(x => x.id === id ? { ...x, active } : x));
  };

  const handleToggleTeacher = async (id, active) => {
    await toggleTeacher(id, active).catch(console.error);
    setTeachers(t => t.map(x => x.id === id ? { ...x, active } : x));
  };

  const studentRows = students.map(s => [
    <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
      <Avatar name={s.name} size={28} />
      {s.name}
    </div>,
    s.userId || `STU-${s.id}`,
    s.department || "—",
    s.email,
    <Badge type={s.active ? "success" : "warning"}>{s.active ? "Active" : "Inactive"}</Badge>,
    <div style={{ display: "flex", gap: 6 }}>
      <Btn size="xs" variant="dark" onClick={() => handleToggleStudent(s.id, !s.active)}>
        {s.active ? "Deactivate" : "Activate"}
      </Btn>
      <Btn size="xs" variant="danger" onClick={() => handleDeleteStudent(s.id)}>🗑 Delete</Btn>
    </div>,
  ]);

  const teacherRows = teachers.map(t => [
    <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
      <Avatar name={t.name} size={28} color={T.accentG} />
      {t.name}
    </div>,
    t.userId || `TCH-${t.id}`,
    t.department || "—",
    t.email,
    <Badge type={t.active ? "success" : "warning"}>{t.active ? "Active" : "Inactive"}</Badge>,
    <div style={{ display: "flex", gap: 6 }}>
      <Btn size="xs" variant="dark" onClick={() => handleToggleTeacher(t.id, !t.active)}>
        {t.active ? "Deactivate" : "Activate"}
      </Btn>
      <Btn size="xs" variant="danger" onClick={() => handleDeleteTeacher(t.id)}>🗑 Delete</Btn>
    </div>,
  ]);

  const parentRows = parents.map(p => [
    <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
      <Avatar name={p.name} size={28} color={T.accentR} />
      {p.name}
    </div>,
    p.userId || `PAR-${p.id}`,
    p.email,
    p.phone || "—",
    <Btn size="xs" variant="danger" onClick={() => handleDeleteParent(p.id)}>🗑 Delete</Btn>,
  ]);

  return (
    <div className="fade-up">
      <PageHeader
        title="Manage Users"
        subtitle="Full system control over all user types"
        actions={[<Btn variant="primary" onClick={() => setModal(true)}>+ Add User</Btn>]}
      />
      <Tabs tabs={["Students", "Teachers", "Parents"]} active={tab} onChange={setTab} />
      <Card>
        {loading ? (
          <div style={{ padding: 32, textAlign: "center", color: T.muted }}>Loading…</div>
        ) : (
          <>
            {tab === "Students" && (
              <Table
                columns={["Student", "ID", "Department", "Email", "Status", "Actions"]}
                rows={studentRows.length ? studentRows : [["No students found", "", "", "", "", ""]]}
              />
            )}
            {tab === "Teachers" && (
              <Table
                columns={["Teacher", "ID", "Department", "Email", "Status", "Actions"]}
                rows={teacherRows.length ? teacherRows : [["No teachers found", "", "", "", "", ""]]}
              />
            )}
            {tab === "Parents" && (
              <Table
                columns={["Parent", "ID", "Email", "Phone", "Actions"]}
                rows={parentRows.length ? parentRows : [["No parents found", "", "", "", ""]]}
              />
            )}
          </>
        )}
      </Card>
      <Modal open={modal} onClose={() => setModal(false)} title="Add New User">
        <Select
          label="User Type"
          options={[
            { value: "student", label: "Student" },
            { value: "teacher", label: "Teacher" },
            { value: "parent",  label: "Parent"  },
          ]}
        />
        <Input label="Full Name"           placeholder="Enter full name" />
        <Input label="Email"               type="email"    placeholder="user@email.com" />
        <Input label="Temporary Password"  type="password" placeholder="Temporary password" />
        <Btn variant="primary" full onClick={() => setModal(false)}>Create User →</Btn>
      </Modal>
    </div>
  );
};


