// ─── FEE MANAGEMENT ───────────────────────────────────────────────────────────
export const AdminFees = () => {
  const [fees, setFees]       = useState([]);
  const [modal, setModal]     = useState(false);
  const [students, setStudents] = useState([]);
  const [loading, setLoading] = useState(false);
  const [form, setForm]       = useState({
    studentId: "", amount: "", dueDate: "", description: "",
  });

  // Revenue summary derived from fees list
  const totalBilled     = fees.reduce((s, f) => s + Number(f.amount      || 0), 0);
  const totalCollected  = fees.filter(f => f.status === "PAID").reduce((s, f) => s + Number(f.paidAmount || f.amount || 0), 0);
  const totalOutstanding = totalBilled - totalCollected;
  const collectionRate  = totalBilled > 0 ? Math.round((totalCollected / totalBilled) * 100) : 0;

  useEffect(() => {
    setLoading(true);
    Promise.all([getAllFees(), getAllStudents()])
      .then(([f, s]) => {
        setFees(Array.isArray(f) ? f : []);
        setStudents(Array.isArray(s) ? s : []);
      })
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  const handleCreate = async () => {
    try {
      const created = await createFee({
        studentId:   Number(form.studentId),
        amount:      form.amount,
        dueDate:     form.dueDate,
        description: form.description,
      });
      setFees(f => [...f, created]);
      setModal(false);
      setForm({ studentId: "", amount: "", dueDate: "", description: "" });
    } catch (err) { alert("Error: " + err.message); }
  };

  const handleMarkPaid = async (id) => {
    try {
      const updated = await markFeePaid(id);
      setFees(f => f.map(x => x.id === id ? updated : x));
    } catch (err) { alert("Error: " + err.message); }
  };

  const feeRows = fees.map(f => [
    f.student?.name || `Student #${f.student?.id}`,
    f.description   || "—",
    `₹${Number(f.amount).toLocaleString("en-IN")}`,
    f.dueDate       || "—",
    <Badge type={f.status === "PAID" ? "success" : f.status === "OVERDUE" ? "danger" : "warning"}>
      {f.status}
    </Badge>,
    f.status !== "PAID"
      ? <Btn size="xs" variant="primary" onClick={() => handleMarkPaid(f.id)}>Mark Paid</Btn>
      : <span style={{ fontSize: 12, color: T.accentG }}>✓ Paid</span>,
  ]);

  return (
    <div className="fade-up">
      <PageHeader
        title="Fee Setup & Management"
        actions={[<Btn variant="primary" onClick={() => setModal(true)}>+ Add Fee</Btn>]}
      />
      <div style={{ display: "grid", gridTemplateColumns: "2fr 1fr", gap: 20 }}>
        <Card>
          {loading ? (
            <div style={{ padding: 32, textAlign: "center", color: T.muted }}>Loading…</div>
          ) : (
            <Table
              columns={["Student", "Description", "Amount", "Due Date", "Status", "Action"]}
              rows={feeRows.length ? feeRows : [["No fees found", "", "", "", "", ""]]}
            />
          )}
        </Card>
        <Card style={{ padding: 24 }}>
          <div style={{ fontFamily: "Syne", fontWeight: 700, marginBottom: 16 }}>Fee Summary</div>
          {[
            ["Total Billed",   `₹${totalBilled.toLocaleString("en-IN")}`,      T.text],
            ["Collected",      `₹${totalCollected.toLocaleString("en-IN")}`,   T.accentG],
            ["Outstanding",    `₹${totalOutstanding.toLocaleString("en-IN")}`, T.accentR],
          ].map(([l, v, c]) => (
            <div key={l} style={{
              display: "flex", justifyContent: "space-between",
              fontSize: 13, padding: "8px 0",
              borderBottom: `1px solid rgba(45,33,96,.4)`,
            }}>
              <span style={{ color: T.muted }}>{l}</span>
              <span style={{ fontFamily: "Syne", fontWeight: 800, color: c }}>{v}</span>
            </div>
          ))}
          <ProgressBar value={collectionRate} color={T.accentG} height={8} />
          <div style={{ fontSize: 11, color: T.muted, marginTop: 6 }}>
            Collection Rate: {collectionRate}%
          </div>
        </Card>
      </div>
      <Modal open={modal} onClose={() => setModal(false)} title="Add Fee">
        <Select
          label="Student *"
          value={form.studentId}
          onChange={e => setForm(f => ({ ...f, studentId: e.target.value }))}
          options={students.map(s => ({ value: String(s.id), label: s.name }))}
        />
        <Input
          label="Amount (₹) *"
          type="number"
          placeholder="Enter amount"
          value={form.amount}
          onChange={e => setForm(f => ({ ...f, amount: e.target.value }))}
        />
        <Input
          label="Description"
          placeholder="e.g. Tuition Q1"
          value={form.description}
          onChange={e => setForm(f => ({ ...f, description: e.target.value }))}
        />
        <Input
          label="Due Date"
          type="date"
          value={form.dueDate}
          onChange={e => setForm(f => ({ ...f, dueDate: e.target.value }))}
        />
        <Btn variant="primary" full onClick={handleCreate}>Save Fee →</Btn>
      </Modal>
    </div>
  );
};


// ─── ANNOUNCEMENTS ────────────────────────────────────────────────────────────
export const AdminAnnouncements = () => {
  const [announcements, setAnnouncements] = useState([]);
  const [modal, setModal]   = useState(false);
  const [loading, setLoading] = useState(false);
  const [form, setForm]     = useState({ title: "", content: "", targetRole: "" });

  useEffect(() => { loadAnnouncements(); }, []);

  const loadAnnouncements = async () => {
    setLoading(true);
    getAllAnnouncements()
      .then(d => setAnnouncements(Array.isArray(d) ? d : []))
      .catch(console.error)
      .finally(() => setLoading(false));
  };

  const handleCreate = async () => {
    try {
      const created = await createAnnouncement({
        title:      form.title,
        content:    form.content,
        targetRole: form.targetRole || null,
      });
      setAnnouncements(a => [created, ...a]);
      setModal(false);
      setForm({ title: "", content: "", targetRole: "" });
    } catch (err) { alert("Error: " + err.message); }
  };

  const handleDelete = async (id) => {
    if (!confirm("Delete this announcement?")) return;
    await deleteAnnouncement(id).catch(console.error);
    setAnnouncements(a => a.filter(x => x.id !== id));
  };

  return (
    <div className="fade-up">
      <PageHeader
        title="Announcements"
        subtitle="Broadcast messages to students, teachers, or everyone"
        actions={[<Btn variant="primary" onClick={() => setModal(true)}>+ New Announcement</Btn>]}
      />
      <Card>
        {loading ? (
          <div style={{ padding: 32, textAlign: "center", color: T.muted }}>Loading…</div>
        ) : announcements.length === 0 ? (
          <div style={{ padding: 32, textAlign: "center", color: T.muted }}>No announcements yet.</div>
        ) : (
          announcements.map(a => (
            <div key={a.id} style={{
              padding: "14px 0",
              borderBottom: `1px solid rgba(45,33,96,.4)`,
              display: "flex", gap: 14, alignItems: "flex-start",
            }}>
              <div style={{
                width: 40, height: 40, background: `${T.primary}18`,
                borderRadius: 9, display: "flex", alignItems: "center",
                justifyContent: "center", fontSize: 20, flexShrink: 0,
              }}>📢</div>
              <div style={{ flex: 1 }}>
                <div style={{ fontWeight: 700, fontSize: 14 }}>{a.title}</div>
                <div style={{ fontSize: 13, color: T.muted, margin: "4px 0" }}>{a.content}</div>
                <div style={{ fontSize: 11, color: T.muted }}>
                  By {a.authorName} ·{" "}
                  {a.targetRole
                    ? <Badge type="info">{a.targetRole}</Badge>
                    : <Badge type="success">Everyone</Badge>}
                </div>
              </div>
              <Btn size="xs" variant="danger" onClick={() => handleDelete(a.id)}>🗑</Btn>
            </div>
          ))
        )}
      </Card>
      <Modal open={modal} onClose={() => setModal(false)} title="New Announcement">
        <Input
          label="Title *"
          placeholder="Announcement title"
          value={form.title}
          onChange={e => setForm(f => ({ ...f, title: e.target.value }))}
        />
        <Input
          label="Content *"
          placeholder="Write your message…"
          value={form.content}
          onChange={e => setForm(f => ({ ...f, content: e.target.value }))}
        />
        <Select
          label="Target Audience"
          value={form.targetRole}
          onChange={e => setForm(f => ({ ...f, targetRole: e.target.value }))}
          options={[
            { value: "",        label: "Everyone (Global)" },
            { value: "STUDENT", label: "Students Only"     },
            { value: "TEACHER", label: "Teachers Only"     },
            { value: "PARENT",  label: "Parents Only"      },
          ]}
        />
        <Btn variant="primary" full onClick={handleCreate}>Post Announcement →</Btn>
      </Modal>
    </div>
  );
};


